async function detectFileLeaks(threadId) {
  const messages = await openai.beta.threads.messages.list(threadId);

  for (const msg of messages.data) {
    if (msg.annotations?.some(ann => ann.type === 'file_citation')) {
      for (const ann of msg.annotations) {
        if (ann.type === 'file_citation') {
          const fileContent = await openai.files.content(ann.file_citation.file_id).text();
          const piiRegex = /\b\d{3}-\d{2}-\d{4}\b|\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g;
          const matches = fileContent.match(piiRegex);
          if (matches) {
            console.log(`Leak in file ${ann.file_citation.file_id}:`, matches.slice(0, 5));
          }
        }
      }
    }
  }
}

