const OpenAI = require('openai');
const openai = new OpenAI();

const piiRegex = /\b\d{3}-\d{2}-\d{4}\b|\b(sk-\w{48})\b/g;

async function pruneSensitiveThread(threadId) {
  const messages = await openai.beta.threads.messages.list(threadId);

  for (const msg of messages.data) {
    const content = msg.content[0]?.text?.value || '';
    if (piiRegex.test(content)) {
      await openai.beta.threads.messages.del(threadId, msg.id);
      console.log(`Pruned sensitive message: ${msg.id}`);
    }
  }
}

// Run after every 10 interactions
setInterval(() => pruneSensitiveThread('thread_abc123'), 60000);
